def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        ppt = Presentation(modified_ppt_path)
        slide_8 = ppt.slides[7]  # Index 7 for slide 8

        proc3_found = False
        for shape in slide_8.shapes:
            if hasattr(shape, 'text_frame') and shape.text_frame:
                text_content = shape.text_frame.text.strip().lower()
                if 'proc 3' in text_content or 'proc3' in text_content:
                    proc3_found = True
                    break

        if proc3_found:
            return "Found shape with 'Proc 3' text on slide 8", 1.0
        else:
            return "No shape with 'Proc 3' text found on slide 8", 0.0

    except Exception as e:
        return f"Error checking for 'Proc 3' text: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Use VLM to check if the Proc 3 box is purple colored
    try:
        slide_8_screenshot = None
        for screenshot in modified_ppt_screenshots:
