                slide_8_screenshot = screenshot
                break

        if not slide_8_screenshot:
            return "Could not find screenshot for slide 8", 0.0

        prompt = """Look at this PowerPoint slide image. Is there a process box or shape labeled 'Proc 3' that appears to be purple in color? 

Respond with either:
        - YES: if there is a 'Proc 3' box/shape that is purple colored
        - NO: if there is no 'Proc 3' box or it is not purple colored

Be specific about what you observe."""

        response = vlm_call(prompt, [slide_8_screenshot.image_path], temperature=0.1)

        if response.strip().upper().startswith('YES'):
            return f"VLM confirmed purple 'Proc 3' box: {response}", 1.0
        else:
            return f"VLM did not confirm purple 'Proc 3' box: {response}", 0.0

    except Exception as e:
        return f"Error checking purple color: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Use VLM to evaluate positioning relative to existing processes
    try:
        slide_8_screenshot = None
        for screenshot in modified_ppt_screenshots:
            if screenshot.slide_number == 8:
                slide_8_screenshot = screenshot
                break

        if not slide_8_screenshot:
            return "Could not find screenshot for slide 8", 0.0

        prompt = """Look at this PowerPoint slide image. I need to verify if a 'Proc 3' process box is positioned appropriately next to other existing process boxes.

Please analyze:
        1. Are there existing process boxes (likely labeled as processes like 'Proc 1', 'Proc 2', etc.)?
        2. Is there a 'Proc 3' box positioned logically next to or near these existing processes?
        3. Does the positioning look intentional and well-aligned with the existing process flow/layout?

Respond with:
        - GOOD: if 'Proc 3' is well-positioned next to existing processes and is placed after 'Proc 2' and before 'Proc n'
        - POOR: if 'Proc 3' is poorly positioned, isolated, or misaligned
        - MISSING: if you cannot find 'Proc 3' or existing processes

Explain your reasoning."""

        response = vlm_call(prompt, [slide_8_screenshot.image_path], temperature=0.1)

        if 'GOOD' in response.upper():
            return f"VLM confirmed good positioning: {response}", 1.0
        elif 'POOR' in response.upper():
            return f"VLM found poor positioning: {response}", 0.5
        else:
            return f"VLM could not confirm proper positioning: {response}", 0.0

    except Exception as e:
        return f"Error checking positioning: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    try:
        # Check if any slides other than slide 8 were modified
        modified_slides = ppt_diff.modified_slides
        added_slides = ppt_diff.added_slides
        removed_slides = ppt_diff.removed_slides

        issues = []

        # Check for added or removed slides
        if added_slides:
            issues.append(f"{len(added_slides)} slides were added")
        if removed_slides:
            issues.append(f"{len(removed_slides)} slides were removed")

        # Check for modifications to slides other than slide 8
        other_slide_modifications = 0
        for old_slide, new_slide in modified_slides:
            if new_slide.slide_number != 8:
                other_slide_modifications += 1

        if other_slide_modifications > 0:
            issues.append(f"{other_slide_modifications} slides other than slide 8 were modified")

        if not issues:
            return "No unintended changes to other slides detected", 1.0
        else:
            return f"Unintended changes detected: {'; '.join(issues)}", 0.0

    except Exception as e:
        return f"Error checking for unintended slide changes: {str(e)}", 0.5

